const items = $input.all();

let prompt = "";
const urls = [];

function extractUrl(str) {
  if (!str) return null;
  const m = String(str).match(/https?:\/\/[^\s",\]\)]+/i);
  return m ? m[0] : null;
}

for (const item of items) {
  const j = item.json || {};

  if (!prompt && j["Image Prompt"]) {
    prompt = j["Image Prompt"];
  }

  for (const key of Object.keys(j)) {
    const maybe = extractUrl(j[key]);
    if (maybe && !urls.includes(maybe)) {
      urls.push(maybe);
    }
  }
}

const payloadObject = {
  model: "nano-banana-pro",
  input: {
    prompt: prompt,
    aspect_ratio: "1:1",
    resolution: "4K",
    output_format: "png",
    image_input: urls.slice(0, 4),
  },
};

// ✅ Pretty-printed, human-readable, same indentation style
return [
  {
    json: {
      payload: JSON.stringify(payloadObject, null, 2),
    },
  },
];

// Get the single incoming item
const item = $input.first().json;

// Initialize image_input array
const imageInputs = [];

// 1️⃣ Always include the template image FIRST
if (typeof item.template_url === 'string' && item.template_url.trim() !== '') {
  imageInputs.push(item.template_url.trim());
}

// 2️⃣ Add image1, image2, image3, etc.
Object.keys(item).forEach((key) => {
  if (
    key.startsWith('image') &&
    key !== 'image_prompts' && // safety: exclude non-image URL objects
    typeof item[key] === 'string' &&
    item[key].trim() !== ''
  ) {
    imageInputs.push(item[key].trim());
  }
});

// Build the payload object
const payloadObject = {
  model: 'nano-banana-pro',
  input: {
    prompt: item.generated_prompt,
    aspect_ratio: '1:1',
    resolution: '4K',
    output_format: 'png',
    image_input: imageInputs
  }
};

// Return a SINGLE item with stringified payload
return [
  {
    json: {
      payload: JSON.stringify(payloadObject, null, 2)
    }
  }
];

